// Build the API request body safely using JSON.stringify
// This properly escapes backslashes, quotes, newlines, etc. in user input
const featureDescription = $input.first().json.featureDescription || '';
const additionalContext = $input.first().json.additionalContext || '';

const prompt = `You are a senior software architect performing technical analysis for a development team.

Given the following feature description, produce a detailed technical analysis as a JSON object.

## Feature Description
${featureDescription}

## Additional Context
${additionalContext}

## Output Format

Respond ONLY with valid JSON matching this schema:

{
  "title": "Short descriptive title",
  "summary": "2-3 sentence executive summary",
  "architecture": {
    "overview": "High-level architecture description",
    "components": [{"name": "...", "type": "frontend|backend|database|infrastructure", "description": "...", "changes": "..."}],
    "dataFlow": "Data flow description"
  },
  "apiContracts": [{"method": "GET|POST|PUT|DELETE", "path": "/api/...", "description": "...", "requestBody": {}, "responseBody": {}, "statusCodes": ["200 - OK"]}],
  "databaseChanges": [{"type": "new-table|alter-table", "entity": "...", "description": "...", "fields": [{"name": "...", "type": "...", "nullable": false}]}],
  "edgeCases": [{"scenario": "...", "impact": "low|medium|high", "mitigation": "..."}],
  "securityConsiderations": ["..."],
  "testingStrategy": {"unitTests": ["..."], "integrationTests": ["..."], "e2eTests": ["..."]},
  "tasks": [{"type": "epic|story|subtask", "summary": "...", "description": "...", "component": "frontend|backend|database|devops|testing", "estimate": "XS|S|M|L|XL", "priority": "Critical|High|Medium|Low", "acceptanceCriteria": ["Given X, when Y, then Z"]}],
  "estimatedComplexity": "low|medium|high",
  "suggestedApproach": "Recommended implementation order"
}

Rules: Tasks should be 1-3 day work items. Include Gherkin acceptance criteria. Be specific, not generic.`;

const model = $env.AI_MODEL || 'openai/gpt-4.1';
const maxTokens = parseInt($env.AI_MAX_TOKENS || '4096', 10);

const requestBody = {
  model,
  max_tokens: maxTokens,
  messages: [{ role: 'user', content: prompt }]
};

const authHeader = 'Bearer ' + ($env.GITHUB_TOKEN || '');

return [{ json: { requestBody, authHeader } }];

// Extract JSON from GitHub Models (OpenAI-compatible) response
const response = $input.first().json;
const content = response.choices[0].message.content;

// Parse the JSON (handle markdown code fences if present)
let jsonStr = content;
if (content.includes('```json')) {
  jsonStr = content.split('```json')[1].split('```')[0].trim();
} else if (content.includes('```')) {
  jsonStr = content.split('```')[1].split('```')[0].trim();
}

let analysis;
try {
  analysis = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse AI response as JSON: ${e.message}\n\nRaw response: ${content.substring(0, 500)}`);
}

// Get variables from earlier node
const vars = $('Set Variables').first().json;

return [{
  json: {
    analysis,
    featureDescription: vars.featureDescription,
    createJiraTasks: vars.createJiraTasks,
    confluenceParentPageId: vars.confluenceParentPageId
  }
}];

// Convert analysis JSON to Confluence-friendly HTML
const { analysis } = $input.first().json;

let html = '';
html += `<h2>Summary</h2><p>${analysis.summary}</p>`;
html += `<h2>Architecture</h2><p>${analysis.architecture.overview}</p>`;
html += `<h3>Components</h3><table><thead><tr><th>Component</th><th>Type</th><th>Description</th><th>Changes</th></tr></thead><tbody>`;
for (const c of analysis.architecture.components || []) {
  html += `<tr><td><strong>${c.name}</strong></td><td><code>${c.type}</code></td><td>${c.description}</td><td>${c.changes}</td></tr>`;
}
html += `</tbody></table>`;
if (analysis.architecture.dataFlow) html += `<h3>Data Flow</h3><p>${analysis.architecture.dataFlow}</p>`;
if (analysis.apiContracts?.length) {
  html += `<h2>API Contracts</h2>`;
  for (const api of analysis.apiContracts) {
    html += `<h3><code>${api.method} ${api.path}</code></h3><p>${api.description}</p>`;
    if (api.statusCodes?.length) html += `<p><strong>Status Codes:</strong> ${api.statusCodes.join(', ')}</p>`;
  }
}
if (analysis.databaseChanges?.length) {
  html += `<h2>Database Changes</h2><table><thead><tr><th>Type</th><th>Entity</th><th>Description</th></tr></thead><tbody>`;
  for (const db of analysis.databaseChanges) html += `<tr><td><code>${db.type}</code></td><td><strong>${db.entity}</strong></td><td>${db.description}</td></tr>`;
  html += `</tbody></table>`;
}
if (analysis.edgeCases?.length) {
  html += `<h2>Edge Cases</h2><table><thead><tr><th>Scenario</th><th>Impact</th><th>Mitigation</th></tr></thead><tbody>`;
  for (const ec of analysis.edgeCases) html += `<tr><td>${ec.scenario}</td><td><code>${ec.impact}</code></td><td>${ec.mitigation}</td></tr>`;
  html += `</tbody></table>`;
}
if (analysis.securityConsiderations?.length) {
  html += `<h2>Security</h2><ul>`;
  for (const s of analysis.securityConsiderations) html += `<li>${s}</li>`;
  html += `</ul>`;
}
if (analysis.tasks?.length) {
  html += `<h2>Task Breakdown</h2><table><thead><tr><th>Type</th><th>Summary</th><th>Component</th><th>Estimate</th><th>Priority</th></tr></thead><tbody>`;
  for (const t of analysis.tasks) html += `<tr><td><code>${t.type}</code></td><td>${t.summary}</td><td><code>${t.component}</code></td><td>${t.estimate}</td><td>${t.priority}</td></tr>`;
  html += `</tbody></table>`;
}
html += `<h2>Overall</h2><p><strong>Complexity:</strong> ${analysis.estimatedComplexity}</p><p><strong>Approach:</strong> ${analysis.suggestedApproach}</p>`;
html += `<hr/><p><em>Generated by <a href="https://github.com/openmindednewby/ai-confluence-pipeline">ai-confluence-pipeline</a> on ${new Date().toISOString().split('T')[0]}</em></p>`;

return [{ json: { html, title: analysis.title, analysis: $input.first().json.analysis, createJiraTasks: $input.first().json.createJiraTasks, confluenceParentPageId: $input.first().json.confluenceParentPageId } }];

const analysis = $('Parse AI Response').first().json.analysis;
const confluencePage = $('Create Confluence Page').first().json;
const confluenceUrl = confluencePage._links?.base + confluencePage._links?.webui;
const tasks = analysis.tasks || [];
const estimateToPoints = { 'XS': 1, 'S': 2, 'M': 3, 'L': 5, 'XL': 8 };
return tasks.map(task => ({ json: { task, storyPoints: estimateToPoints[task.estimate] || 3, confluenceUrl, pageTitle: analysis.title } }));

const confluencePage = $('Create Confluence Page').first().json;
const analysis = $('Parse AI Response').first().json.analysis;
const jiraIssues = $input.all().map(item => item.json);
return [{ json: { success: true, confluencePage: { id: confluencePage.id, title: confluencePage.title, url: (confluencePage._links?.base || '') + (confluencePage._links?.webui || '') }, jiraIssues: jiraIssues.map(issue => ({ key: issue.key, summary: issue.fields?.summary, url: `${process.env.JIRA_BASE_URL}/browse/${issue.key}` })), taskCount: jiraIssues.length, complexity: analysis.estimatedComplexity } }];

const confluencePage = $('Create Confluence Page').first().json;
const analysis = $('Parse AI Response').first().json.analysis;
return [{ json: { success: true, confluencePage: { id: confluencePage.id, title: confluencePage.title, url: (confluencePage._links?.base || '') + (confluencePage._links?.webui || '') }, jiraIssues: [], taskCount: 0, complexity: analysis.estimatedComplexity, note: 'Jira task creation was skipped (createJiraTasks=false)' } }];
